  luge:{emoji:'🛷',label:'Luge',tipo:'conjunto',puntuacion:'marca',parciales:[],tiempoParcial:null,penalizaciones:["Penalización de tiempo (se agregan segundos)"],descalificaciones:["salida irregular o antes de la señal oficial, peso ilegal del trineo, modificaciones no autorizadas, ayuda externa, incumplimiento de reglamento técnico, dopaje, no completar el recorrido correctamente."],estadisticasComplementarias:["Salida irregular / salida falsa: advertencia o descalificación de la bajada\n\nPenalización de tiempo: se agregan segundos al tiempo total acumulado\n\nRepetición de bajada (si aplica por interferencia externa): se invalida el tiempo anterior y se realiza nueva bajada\n\nDescalificación (DSQ): eliminación de la bajada o de la competencia completa\n\nDescalificación por equipamiento: exclusión por peso ilegal, modificaciones no autorizadas o trineo fuera de especificaciones\n\nDescalificación por seguridad: eliminación por conducta peligrosa o incumplimiento de normas de seguridad\n\nDescalificación por dopaje: exclusión oficial y anulación de resultados\n\nAdvertencia oficial: sanción disciplinaria; reincidencia puede derivar en penalización o DSQ"],permiteTiempoExtra:false},
  marcha_atl_tica:{emoji:'🚶',label:'Marcha Atlética',tipo:'individual',puntuacion:'marca',parciales:[],tiempoParcial:null,penalizaciones:[],descalificaciones:["Pérdida de contacto\nRodilla flexionada\nAcumulación de tarjetas rojas\nAyuda externa"],estadisticasComplementarias:["\"-Observación del juez: señal preventiva por posible infracción técnica; sin consecuencia directa.\n-Advertencia verbal: llamado de atención; sin consecuencia directa.\n-Tarjeta amarilla (Warning): infracción visible de técnica; no afecta tiempo ni posición.\n-Tarjeta roja: propuesta de descalificación por:\n-Pérdida de contacto visible.\n-Rodilla flexionada en apoyo.\n-Zona de penalización (Penalty Zone): detención obligatoria por tiempo reglamentario tras acumulación de tarjetas rojas (según reglamento vigente).\"\n\""],permiteTiempoExtra:false},
