  rugby:{emoji:'🏉',label:'Rugby',tipo:'conjunto',puntuacion:'acumulativa_tiempos',parciales:["1er Tiempo", "2do Tiempo"],tiempoParcial:'40 min',penalizaciones:[],descalificaciones:["Tarjeta roja"],estadisticasComplementarias:["Tarjeta Amarilla: Suspensión de 10 minutos cronometrados. El equipo juega con 14.\nTarjeta Roja: Expulsión definitiva.\nPenal (Penalty): Permite patear a palos (3 puntos), buscar el touch (lateral) o jugar rápido.\nFree Kick (Tiro Libre): Por infracciones técnicas (ej. demora en el scrum). No se puede anotar puntos directamente ni pedir palos.", "Tarjeta Amarilla: Suspensión de 2 minutos. En un juego tan corto, esto suele ser letal para el marcador.\nTarjeta Roja: Expulsión por el resto del torneo"],permiteTiempoExtra:true,tiempoExtraConfig:{parciales:'2 prórrogas de 10 min hasta definir ganador',duracion:'10 min'},pruebas:{'rugby_sevens_competencia_de_rugby_sevens':{label:'Competencia de Rugby Sevens',modalidad:'Rugby Sevens',parciales:["1er Tiempo", "2do Tiempo"],tiempoParcial:'7 min'}}},
